@startuml
title Al's Class Diagram

package com {
  package dekinci {
    package eden {
      package model {
        package animal {
          package ai {

            class AnimalVision {
              - grass : double[]
              - hares : double[]
              - wolfes : double[]
              - land : double[]
              - water : double[]
              + AnimalVision()
              + getjoined()
            }

            class DoubleToGrayCode {
              - minValue : int
              - maxValue : int
              - size : int
              - bits : int
              - pieces : int
              + {static} doubleToGC()
              + {static} gCToDouble()
            }

            class Brain {
              + Brain()
              + Brain()
              + breed()
              + makeDecision()
            }

            class VisionFactory {
              - animalSight : int
              + VisionFactory()
              + seeBlocks()
              + seeGrass()
              + seeAnimals()
              - getPoint()
            }

            class Genotype {
              - genes : int[]
              + Genotype()
              # getGenes()
              + breed()
              - crossover()
              - arrayExchange()
              - bitExchange()
              - mutation()
            }

            class NeuralNetwork {
              - inputLayer : double[][]
              - innerLayers : double[][][]
              - outputLayer : double[][]
              - inputSize : int
              - innerSize : int
              - outputSize : int
              + NeuralNetwork()
              + NeuralNetwork()
              + genotype()
              + calculate()
              - activationF()
            }

          }
        }
      }
    }
  }

  class Coordinate {
  }

  class WorldMap {
  }

  class AnimalManager {
  }
}

Brain o-- NeuralNetwork : neuralNetwork

VisionFactory --> Coordinate
VisionFactory --> WorldMap : worldMap
VisionFactory --> AnimalManager : manager

@enduml
